import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.CO0llY-g.js";const g=JSON.parse('{"title":"CAS学习教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1780974589000}'),l={name:"guide/index.md"};function o(n,a,s,h,d,u){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="cas学习教程" tabindex="-1">CAS学习教程 <a class="header-anchor" href="#cas学习教程" aria-label="Permalink to &quot;CAS学习教程&quot;">​</a></h1><p>欢迎来到CAS（计算机代数系统）学习教程！本教程将带您从入门到高级，系统学习符号计算的核心概念和应用。</p><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><h3 id="🎯-入门级-符号计算基础" tabindex="-1">🎯 入门级：符号计算基础 <a class="header-anchor" href="#🎯-入门级-符号计算基础" aria-label="Permalink to &quot;🎯 入门级：符号计算基础&quot;">​</a></h3><p><strong>目标</strong>：掌握符号计算的基本概念和操作</p><ul><li><strong>变量与表达式定义</strong>：学习如何在CAS中定义符号变量和表达式</li><li><strong>基本代数运算</strong>：掌握化简、展开、因式分解等基本操作</li><li><strong>方程求解</strong>：学习求解一元和多元代数方程</li><li><strong>函数定义与绘图</strong>：定义符号函数并绘制图形</li></ul><p><strong>预计学习时间</strong>：2-3小时</p><p><a href="/Maxima-and-Octave-CAS-tutorial/guide/01-symbolic-basics/">开始学习 →</a></p><hr><h3 id="📐-基础级-微积分基础" tabindex="-1">📐 基础级：微积分基础 <a class="header-anchor" href="#📐-基础级-微积分基础" aria-label="Permalink to &quot;📐 基础级：微积分基础&quot;">​</a></h3><p><strong>目标</strong>：掌握符号微积分的核心概念</p><ul><li><strong>极限计算</strong>：学习计算各种类型的极限</li><li><strong>导数与微分</strong>：掌握符号导数和微分运算</li><li><strong>积分计算</strong>：学习不定积分和定积分的符号计算</li><li><strong>级数展开</strong>：掌握泰勒级数和其他级数展开</li></ul><p><strong>预计学习时间</strong>：3-4小时</p><p><a href="/Maxima-and-Octave-CAS-tutorial/guide/02-calculus/">开始学习 →</a></p><hr><h3 id="🔢-进阶级-线性代数与微分方程" tabindex="-1">🔢 进阶级：线性代数与微分方程 <a class="header-anchor" href="#🔢-进阶级-线性代数与微分方程" aria-label="Permalink to &quot;🔢 进阶级：线性代数与微分方程&quot;">​</a></h3><p><strong>目标</strong>：掌握符号线性代数和微分方程求解</p><h4 id="线性代数" tabindex="-1">线性代数 <a class="header-anchor" href="#线性代数" aria-label="Permalink to &quot;线性代数&quot;">​</a></h4><ul><li><strong>矩阵定义与基本运算</strong>：学习符号矩阵的创建和运算</li><li><strong>线性方程组求解</strong>：掌握符号求解线性方程组的方法</li><li><strong>特征值与特征向量</strong>：学习计算矩阵的特征值和特征向量</li><li><strong>矩阵分解</strong>：掌握LU、QR等矩阵分解方法</li></ul><h4 id="微分方程" tabindex="-1">微分方程 <a class="header-anchor" href="#微分方程" aria-label="Permalink to &quot;微分方程&quot;">​</a></h4><ul><li><strong>常微分方程（ODE）求解</strong>：学习符号求解常微分方程</li><li><strong>偏微分方程（PDE）基础</strong>：了解偏微分方程的符号求解</li><li><strong>数值解法与符号解法对比</strong>：理解两种方法的优缺点</li><li><strong>边值问题</strong>：学习求解边值问题</li></ul><p><strong>预计学习时间</strong>：6-8小时</p><p><a href="/Maxima-and-Octave-CAS-tutorial/guide/03-linear-algebra/">开始学习线性代数 →</a> | <a href="/Maxima-and-Octave-CAS-tutorial/guide/04-differential-equations/">开始学习微分方程 →</a></p><hr><h3 id="🚀-高级-物理问题应用" tabindex="-1">🚀 高级：物理问题应用 <a class="header-anchor" href="#🚀-高级-物理问题应用" aria-label="Permalink to &quot;🚀 高级：物理问题应用&quot;">​</a></h3><p><strong>目标</strong>：将CAS应用于解决高级物理问题</p><h4 id="泛函分析应用" tabindex="-1">泛函分析应用 <a class="header-anchor" href="#泛函分析应用" aria-label="Permalink to &quot;泛函分析应用&quot;">​</a></h4><ul><li><strong>变分法基础</strong>：学习变分法的基本原理</li><li><strong>欧拉-拉格朗日方程</strong>：掌握推导和求解欧拉-拉格朗日方程</li><li><strong>泛函极值问题</strong>：学习求解泛函极值问题</li><li><strong>在力学中的应用</strong>：将变分法应用于经典力学</li></ul><h4 id="流体力学应用" tabindex="-1">流体力学应用 <a class="header-anchor" href="#流体力学应用" aria-label="Permalink to &quot;流体力学应用&quot;">​</a></h4><ul><li><strong>流体力学基本方程</strong>：学习Navier-Stokes方程</li><li><strong>流函数与势函数</strong>：掌握流函数和势函数的概念</li><li><strong>简单流动问题的符号解</strong>：求解简单的流动问题</li><li><strong>量纲分析与相似性</strong>：学习量纲分析和相似性原理</li><li><strong>瑞利空化泡问题</strong>：学习不可压缩流体中空泡的瞬态问题</li></ul><p><strong>预计学习时间</strong>：8-10小时</p><p><a href="/Maxima-and-Octave-CAS-tutorial/guide/05-functional-analysis/">开始学习泛函分析 →</a> | <a href="/Maxima-and-Octave-CAS-tutorial/guide/06-fluid-mechanics/">开始学习流体力学 →</a></p><hr><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="_1-循序渐进" tabindex="-1">1. 循序渐进 <a class="header-anchor" href="#_1-循序渐进" aria-label="Permalink to &quot;1. 循序渐进&quot;">​</a></h3><p>按照入门→基础→进阶→高级的顺序学习，每个级别都建立在前一级别的基础上。</p><h3 id="_2-动手实践" tabindex="-1">2. 动手实践 <a class="header-anchor" href="#_2-动手实践" aria-label="Permalink to &quot;2. 动手实践&quot;">​</a></h3><p>每个主题都包含代码示例，务必在Octave和Maxima中亲自运行这些代码。</p><h3 id="_3-对比学习" tabindex="-1">3. 对比学习 <a class="header-anchor" href="#_3-对比学习" aria-label="Permalink to &quot;3. 对比学习&quot;">​</a></h3><p>同时学习Octave和Maxima的实现，理解它们的设计哲学和优缺点。</p><h3 id="_4-理解概念" tabindex="-1">4. 理解概念 <a class="header-anchor" href="#_4-理解概念" aria-label="Permalink to &quot;4. 理解概念&quot;">​</a></h3><p>不要只是复制代码，要理解每个操作背后的数学原理。</p><h3 id="_5-扩展应用" tabindex="-1">5. 扩展应用 <a class="header-anchor" href="#_5-扩展应用" aria-label="Permalink to &quot;5. 扩展应用&quot;">​</a></h3><p>尝试将学到的知识应用到自己的研究或项目中。</p><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><h3 id="数学基础" tabindex="-1">数学基础 <a class="header-anchor" href="#数学基础" aria-label="Permalink to &quot;数学基础&quot;">​</a></h3><ul><li>高中数学（代数、三角函数、基本微积分）</li><li>线性代数基础（矩阵、向量）</li><li>微积分基础（极限、导数、积分）</li></ul><h3 id="编程基础" tabindex="-1">编程基础 <a class="header-anchor" href="#编程基础" aria-label="Permalink to &quot;编程基础&quot;">​</a></h3><ul><li>基本的编程概念（变量、循环、函数）</li><li>有Octave/MATLAB或Python经验更佳</li></ul><h3 id="物理基础-高级章节需要" tabindex="-1">物理基础（高级章节需要） <a class="header-anchor" href="#物理基础-高级章节需要" aria-label="Permalink to &quot;物理基础（高级章节需要）&quot;">​</a></h3><ul><li>经典力学基础</li><li>流体力学基础概念</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-我需要同时安装octave和maxima吗" tabindex="-1">Q: 我需要同时安装Octave和Maxima吗？ <a class="header-anchor" href="#q-我需要同时安装octave和maxima吗" aria-label="Permalink to &quot;Q: 我需要同时安装Octave和Maxima吗？&quot;">​</a></h3><p>A: 建议同时安装，这样可以对比学习两种CAS系统。如果只能安装一个，Octave对初学者更友好。</p><h3 id="q-这些代码可以在matlab中运行吗" tabindex="-1">Q: 这些代码可以在MATLAB中运行吗？ <a class="header-anchor" href="#q-这些代码可以在matlab中运行吗" aria-label="Permalink to &quot;Q: 这些代码可以在MATLAB中运行吗？&quot;">​</a></h3><p>A: 大部分Octave代码可以在MATLAB中运行，但MATLAB需要单独的Symbolic Math Toolbox。</p><h3 id="q-学习这些内容需要多长时间" tabindex="-1">Q: 学习这些内容需要多长时间？ <a class="header-anchor" href="#q-学习这些内容需要多长时间" aria-label="Permalink to &quot;Q: 学习这些内容需要多长时间？&quot;">​</a></h3><p>A: 完整学习预计需要20-30小时，建议每天学习2-3小时，持续2-3周。</p><h3 id="q-我可以跳过某些章节吗" tabindex="-1">Q: 我可以跳过某些章节吗？ <a class="header-anchor" href="#q-我可以跳过某些章节吗" aria-label="Permalink to &quot;Q: 我可以跳过某些章节吗？&quot;">​</a></h3><p>A: 可以，但建议至少完成入门级和基础级，再根据兴趣选择进阶和高级内容。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>准备好开始学习了吗？从<a href="/Maxima-and-Octave-CAS-tutorial/guide/01-symbolic-basics/">符号计算基础</a>开始您的CAS学习之旅！</p><p><a href="/Maxima-and-Octave-CAS-tutorial/guide/01-symbolic-basics/">开始学习 →</a></p>',63)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
